// ==========================================
// 2. TRADUTTORE AUTOMATICO: Raggruppa per Squadra e Anno
// ==========================================
const squadreStoriche = [];
const squadreMappa = {};

databaseGrezz.forEach(giocatore => {
  // Unisce il nome del club e l'anno (es. "Napoli 2023")
  const nomeSquadra = giocatore.club_name + " 20" + giocatore.fifa_version; 
  
  if(!squadreMappa[nomeSquadra]) {
    squadreMappa[nomeSquadra] = { nome: nomeSquadra, giocatori: [] };
    squadreStoriche.push(squadreMappa[nomeSquadra]);
  }
  
  squadreMappa[nomeSquadra].giocatori.push({
    nome: giocatore.short_name,       
    ruolo: giocatore.player_positions, 
    voto: giocatore.overall           
  });
});

// ==========================================
// 3. COLLEGAMENTI ALLA GRAFICA E CONFIGURAZIONE MODULI
// ==========================================
const bottoneSpin = document.getElementById("bottone-spin");
const testoPesca = document.querySelector("#squadra-pescata h2");
const contenitoreRosa = document.getElementById("contenitore-rosa");
const selettoreModulo = document.getElementById("scelta-modulo");
const campoDinamico = document.getElementById("campo-dinamico");
const bottoneSimula = document.getElementById("bottone-simula");

let giocatoreInAttesa = null; // Memoria per il giocatore cliccato

const moduli = {
  "4-3-3": [
    { linea: "attacco", ruoli: ["LW", "ST", "RW"] },
    { linea: "centrocampo", ruoli: ["CM", "CM", "CM"] },
    { linea: "difesa", ruoli: ["LB", "CB", "CB", "RB"] },
    { linea: "portiere", ruoli: ["GK"] }
  ],
  "4-4-2": [
    { linea: "attacco", ruoli: ["ST", "ST"] },
    { linea: "centrocampo", ruoli: ["LM", "CM", "CM", "RM"] },
    { linea: "difesa", ruoli: ["LB", "CB", "CB", "RB"] },
    { linea: "portiere", ruoli: ["GK"] }
  ],
  "3-5-2": [
    { linea: "attacco", ruoli: ["ST", "ST"] },
    { linea: "centrocampo", ruoli: ["LM", "CM", "CDM", "CM", "RM"] },
    { linea: "difesa", ruoli: ["CB", "CB", "CB"] },
    { linea: "portiere", ruoli: ["GK"] }
  ]
};

// ==========================================
// 4. DISEGNO DEL CAMPO E ASSEGNAZIONE CLICK
// ==========================================
function disegnaCampo(nomeModulo) {
  if (!campoDinamico) return;
  campoDinamico.innerHTML = ""; 
  giocatoreInAttesa = null; 
  const schema = moduli[nomeModulo];
  
  schema.forEach(riga => {
    const divRiga = document.createElement("div");
    divRiga.className = `riga-campo ${riga.linea}`;
    
    riga.ruoli.forEach(ruolo => {
      const slot = document.createElement("div");
      slot.className = "slot-giocatore";
      slot.setAttribute("data-ruolo", ruolo); 
      slot.innerHTML = `${ruolo}<br>Vuoto`;

      // Posiziona il giocatore se lo slot è verde
      slot.addEventListener("click", function() {
        if (giocatoreInAttesa && this.classList.contains("slot-evidenziato")) {
          this.innerHTML = giocatoreInAttesa.nome + "<br><b>" + giocatoreInAttesa.voto + "</b>";
          this.style.backgroundColor = "#e67e22"; 
          this.style.borderColor = "#ffb703";
          
          document.querySelectorAll(".slot-giocatore").forEach(s => s.classList.remove("slot-evidenziato"));
          
          testoPesca.innerText = "Schierato! Gira ancora la ruota.";
          contenitoreRosa.innerHTML = ""; 
          giocatoreInAttesa = null; 
        }
      });

      divRiga.appendChild(slot);
    });
    
    campoDinamico.appendChild(divRiga);
  });
}

if(selettoreModulo) {
  disegnaCampo(selettoreModulo.value);
  selettoreModulo.addEventListener("change", function() {
    disegnaCampo(this.value);
  });
}

// ==========================================
// 5. LOGICA DEL BOTTONE SPIN
// ==========================================
if(bottoneSpin) {
    bottoneSpin.addEventListener("click", function() {
      const indiceCasuale = Math.floor(Math.random() * squadreStoriche.length);
      const squadraScelta = squadreStoriche[indiceCasuale];
      testoPesca.innerText = "Hai pescato: " + squadraScelta.nome;
      
      contenitoreRosa.innerHTML = "";
      giocatoreInAttesa = null; 
      document.querySelectorAll(".slot-giocatore").forEach(s => s.classList.remove("slot-evidenziato"));
      
      squadraScelta.giocatori.forEach(giocatore => {
         const btn = document.createElement("button");
         btn.className = "carta-giocatore";
         btn.innerText = giocatore.nome + " (" + giocatore.ruolo + ") - " + giocatore.voto;
         btn.onclick = function() {
            accendiSlotValidi(giocatore);
         };
         contenitoreRosa.appendChild(btn);
      });
    });
}

// ==========================================
// 6. TOLLERANZA RUOLI (Illumina slot adatti)
// ==========================================
function accendiSlotValidi(giocatore) {
  const ruoliOriginali = giocatore.ruolo.split(",").map(r => r.trim());
  let ruoliEspansi = [];
  
  ruoliOriginali.forEach(ruolo => {
    ruoliEspansi.push(ruolo); 
    
    if (["CM", "CAM", "CDM"].includes(ruolo)) ruoliEspansi.push("CM", "CAM", "CDM");
    if (["LM", "LW"].includes(ruolo)) ruoliEspansi.push("LM", "LW");
    if (["RM", "RW"].includes(ruolo)) ruoliEspansi.push("RM", "RW");
    if (["CF", "CAM"].includes(ruolo)) ruoliEspansi.push("ST");
  });

  const slotCampoCorrenti = document.querySelectorAll(".slot-giocatore");
  let slotTrovati = 0;

  slotCampoCorrenti.forEach(s => s.classList.remove("slot-evidenziato"));

  slotCampoCorrenti.forEach(slot => {
    const ruoloRichiesto = slot.getAttribute("data-ruolo");
    if (ruoliEspansi.includes(ruoloRichiesto) && slot.innerText.includes("Vuoto")) {
      slot.classList.add("slot-evidenziato");
      slotTrovati++;
    }
  });

  if (slotTrovati > 0) {
    giocatoreInAttesa = giocatore; 
    testoPesca.innerText = "Scegli dove posizionarlo: clicca su uno degli slot verdi lampeggianti!";
  } else {
    alert("Impossibile schierarlo! Questo giocatore può fare solo: " + ruoliOriginali.join(" o ") + " e non ci sono posizioni libere compatibili.");
  }
}

// ==========================================
// 7. SIMULAZIONE FINALE DEL CAMPIONATO (Realismo Massimo)
// ==========================================
if(bottoneSimula) {
    bottoneSimula.addEventListener("click", function() {
      const slotCampoCorrenti = document.querySelectorAll(".slot-giocatore");
      let giocatoriInCampo = 0;
      let sommaVoti = 0;

      slotCampoCorrenti.forEach(slot => {
        if (!slot.innerText.includes("Vuoto")) {
          giocatoriInCampo++;
          const testoSlot = slot.innerHTML;
          const voto = parseInt(testoSlot.split("<b>")[1].split("</b>")[0]);
          sommaVoti += voto;
        }
      });

      if (giocatoriInCampo < 11) {
        alert("❌ Attenzione! Devi completare tutti gli 11 ruoli sul campo prima di far partire la simulazione delle 38 partite!");
        return; 
      }

      const mediaSquadra = Math.round(sommaVoti / 11);
      let vittorie = 0, pareggi = 0, sconfitte = 0;

      // Motore basato sui punti
      if (mediaSquadra >= 89) {
        vittorie = Math.floor(Math.random() * 5) + 34; // 34 - 38
      } else if (mediaSquadra >= 86) {
        vittorie = Math.floor(Math.random() * 6) + 27; // 27 - 32
      } else if (mediaSquadra >= 82) {
        vittorie = Math.floor(Math.random() * 5) + 21; // 21 - 25
      } else if (mediaSquadra >= 78) {
        vittorie = Math.floor(Math.random() * 6) + 14; // 14 - 19
      } else if (mediaSquadra >= 74) {
        vittorie = Math.floor(Math.random() * 5) + 9;  // 9 - 13
      } else {
        vittorie = Math.floor(Math.random() * 5) + 4;  // 4 - 8
      }

      const partiteRimanenti = 38 - vittorie;

      // Calcolo pareggi e sconfitte in base al livello
      if (mediaSquadra >= 85) {
        sconfitte = Math.floor(Math.random() * 3); 
        pareggi = partiteRimanenti - sconfitte;
      } else if (mediaSquadra >= 78) {
        pareggi = Math.floor(partiteRimanenti / 2) + Math.floor(Math.random() * 3) - 1;
        sconfitte = partiteRimanenti - pareggi;
      } else {
        pareggi = Math.floor(Math.random() * (partiteRimanenti / 2.5));
        sconfitte = partiteRimanenti - pareggi;
      }

      if (pareggi < 0) pareggi = 0;
      if (sconfitte < 0) sconfitte = 0;

      const puntiTotali = (vittorie * 3) + pareggi;

      let titolo = "";
      if (vittorie === 38) {
        titolo = "👑 LEGGENDA ASSOLUTA! RECORD STORICO DI 38-0-0!";
      } else if (puntiTotali >= 90) {
        titolo = "🏆 CAMPIONI D'ITALIA! Una stagione clamorosa e scudetto vinto.";
      } else if (puntiTotali >= 70) {
        titolo = "🇪🇺 OBIETTIVO CHAMPIONS RAGGIUNTO! Ottimo lavoro del Mister.";
      } else if (puntiTotali >= 50) {
        titolo = "😐 METÀ CLASSIFICA. Stagione anonima, i tifosi volevano di più.";
      } else {
        titolo = "📉 DISASTRO E RETROCESSIONE. Sei stato esonerato con disonore.";
      }

      alert(`${titolo}\n\n⭐ Media Valutazione Squadra: ${mediaSquadra}\n\nRisultato Finale:\n✅ Vittorie: ${vittorie}\n➖ Pareggi: ${pareggi}\n❌ Sconfitte: ${sconfitte}\n\n📊 PUNTI TOTALI: ${puntiTotali}`);
    });
}
